import{_ as a,c as e,o as n,O as o}from"./chunks/framework.0d343703.js";const d=JSON.parse('{"title":"闭包的理解与应用","description":"","frontmatter":{},"headers":[],"relativePath":"articles/闭包.md"}'),t={name:"articles/闭包.md"},l=o(`<h1 id="闭包的理解与应用" tabindex="-1">闭包的理解与应用 <a class="header-anchor" href="#闭包的理解与应用" aria-label="Permalink to &quot;闭包的理解与应用&quot;">​</a></h1><h2 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;定义&quot;">​</a></h2><ul><li><strong>Closure (computer programming), an abstraction binding a function to its scope（摘自wiki）</strong></li><li>闭包（Closure），又称为词法闭包（Lexical Closure）或函数闭包（function closure）。</li><li>是在支持头等函数的编程语言中，实习词法绑定的一种技术。</li><li>闭包在实现上是一个结构体，它存储了一个函数和一个关联环境</li><li>闭包跟函数最大的区别在于当捕捉闭包的时候，它的自由变量会在捕捉是被确定，这样即使脱离了捕捉时的-上下文，它也能照常运行。</li></ul><p>这样看还是非常的晦涩难懂，所以我们逐步分析理解。先用一个案例来表现闭包：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#A6ACCD;">var name = &quot;foo&quot;;</span></span>
<span class="line"><span style="color:#A6ACCD;">function foo(){</span></span>
<span class="line"><span style="color:#A6ACCD;"> var message = &quot;Hello World&quot;;</span></span>
<span class="line"><span style="color:#A6ACCD;">   console.log(message,name);</span></span>
<span class="line"><span style="color:#A6ACCD;">}</span></span></code></pre></div><p>如果学习过c、c++等语言的读者就会发现，在函数中要想使用函数之外定义的变量，必须在调用时将以实参的形式传入函数。</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#A6ACCD;">var name = &quot;foo&quot;;</span></span>
<span class="line"><span style="color:#A6ACCD;">function foo(name){</span></span>
<span class="line"><span style="color:#A6ACCD;"> var message = &quot;Hello World&quot;;</span></span>
<span class="line"><span style="color:#A6ACCD;">   console.log(message,name);</span></span>
<span class="line"><span style="color:#A6ACCD;">}</span></span></code></pre></div><p><strong>这就是js不同之处，也就是闭包起到了作用</strong></p><ul><li>在JavaScript中，每当创建一个函数，闭包就会在函数创建的同时被创建出来。</li><li>闭包可以在一个内层函数中访问到其外层函数的作用域。</li></ul><p><strong>通俗的说，一个函数如果它可以访问外层作用域的自由变量，那么这个函数与其作用域就是一个闭包。</strong></p><h2 id="基础原理解析" tabindex="-1">基础原理解析 <a class="header-anchor" href="#基础原理解析" aria-label="Permalink to &quot;基础原理解析&quot;">​</a></h2><p>这一部分笔者想要用自己的理解，来帮助大家了解闭包。甚至这一部分的理解，也可以引申到原型链。 <strong>首先来了解概念GO和AO和VO</strong></p><ul><li>GO(Global Object):其包含全局执行的上下文内容。</li><li>AO(Activation Object ):其包含了函数执行期的上下文内容。</li><li>VO(variable object):变量对象 AO是一个即时的存储容器，函数执行完毕以后，AO是要销毁的。（但是有一种情况例外，那就是闭包）</li></ul><p>1、先进行函数声明（未赋值）AO 2、执行代码</p><h2 id="执行上下文包含的属性-this-作用域链-变量对象" tabindex="-1">执行上下文包含的属性 this 作用域链 变量对象 <a class="header-anchor" href="#执行上下文包含的属性-this-作用域链-变量对象" aria-label="Permalink to &quot;执行上下文包含的属性  this 作用域链 变量对象&quot;">​</a></h2><p>因此当在函数内找变量时，在AO中先进行寻找，找不到的情况下会继续向上寻找直到找到GO</p><h2 id="闭包用法" tabindex="-1">闭包用法 <a class="header-anchor" href="#闭包用法" aria-label="Permalink to &quot;闭包用法&quot;">​</a></h2><h3 id="_1-返回值-最常用的" tabindex="-1">1.返回值 最常用的 <a class="header-anchor" href="#_1-返回值-最常用的" aria-label="Permalink to &quot;1.返回值 最常用的&quot;">​</a></h3><p>function fn(){ var name=&quot;hello&quot;; return function(){ return name; } } var fnc = fn(); console.log(fnc())//hello</p><h3 id="函数赋值" tabindex="-1">函数赋值 <a class="header-anchor" href="#函数赋值" aria-label="Permalink to &quot;函数赋值&quot;">​</a></h3><p>var fn2; function fn(){ var name=&quot;hello&quot;;//将函数赋值给 fn2 fn2 = function(){ return name; } } fn()//要先执行进行赋值， console.log(fn2())//执行输出 fn2</p><h3 id="函数参数" tabindex="-1">函数参数 <a class="header-anchor" href="#函数参数" aria-label="Permalink to &quot;函数参数&quot;">​</a></h3><p>function fn(){ var name=&quot;hello&quot;; return function callback(){ return name; } } var fn1 = fn()//执行函数将返回值（callback 函数）赋值给 fn1， function fn2(f){ //将函数作为参数传入 console.log(f());//执行函数，并输出 } fn2(fn1)//执行输出 fn2</p><h3 id="iife-自执行函数" tabindex="-1">IIFE 自执行函数 <a class="header-anchor" href="#iife-自执行函数" aria-label="Permalink to &quot;IIFE 自执行函数&quot;">​</a></h3><p>(function(){ var name=&quot;hello&quot;; var fn1= function(){ return name; } //直接在自执行函数里面调用 fn2，将 fn1 作为参数传入 fn2(fn1); })() function fn2(f){ //将函数作为参数传入 console.log(f());//执行函数，并输出 }</p><h3 id="循环赋值" tabindex="-1">循环赋值 <a class="header-anchor" href="#循环赋值" aria-label="Permalink to &quot;循环赋值&quot;">​</a></h3><p>//每秒执行 1 次，分别输出 1-10 for(var i=1;i&lt;=10;i++){ (function(j){//j 来接收 setTimeout(function(){ console.log(j); },j*1000); })(i)//i 作为实参传入 }</p><h3 id="gette-和-setter" tabindex="-1">gette 和 setter <a class="header-anchor" href="#gette-和-setter" aria-label="Permalink to &quot;gette 和 setter&quot;">​</a></h3><p>function fn(){ var name=&#39;hello&#39; setName=function(n){ name = n; } getName=function(){ return name; }//将 setName，getName 作为对象的属性返回 return { setName:setName, getName:getName } } var fn1 = fn();//返回对象，属性 setName 和 getName 是两个函数 console.log(fn1.getName());//getter fn1.setName(&#39;world&#39;);//setter 修改闭包里面的 name console.log(fn1.getName());//getter</p><h3 id="迭代器-执行一次函数往下取一个值" tabindex="-1">迭代器（执行一次函数往下取一个值） <a class="header-anchor" href="#迭代器-执行一次函数往下取一个值" aria-label="Permalink to &quot;迭代器（执行一次函数往下取一个值）&quot;">​</a></h3><p>var arr =[&#39;aa&#39;,&#39;bb&#39;,&#39;cc&#39;]; function incre(arr){ var i=0; return function(){ //这个函数每次被执行都返回数组 arr 中 i 下标对应的元素 return arr[i++] || &#39;数组值已经遍历完&#39;; } } var next = incre(arr); console.log(next());//aa console.log(next());//bb console.log(next());//cc console.log(next());//数组值已经遍历完</p><h3 id="首次区分-相同的参数-函数不会重复执行" tabindex="-1">首次区分（相同的参数，函数不会重复执行） <a class="header-anchor" href="#首次区分-相同的参数-函数不会重复执行" aria-label="Permalink to &quot;首次区分（相同的参数，函数不会重复执行）&quot;">​</a></h3><p>var fn = (function(){ var arr=[];//用来缓存的数组 return function(val){ if(arr.indexOf(val)==-1){//缓存中没有则表示需要执行 arr.push(val);//将参数 push 到缓存数组中 console.log(&#39;函数被执行了&#39;,arr);//这里写想要执行的函数 }else{ console.log(&#39;此次函数不需要执行&#39;); } console.log(&#39;函数调用完打印一下，方便查看已缓存的数组：&#39;,arr); } })(val); fn(10); fn(10); fn(1000); fn(200); fn(1000);</p><h3 id="缓存" tabindex="-1">缓存 <a class="header-anchor" href="#缓存" aria-label="Permalink to &quot;缓存&quot;">​</a></h3><p>//比如求和操作，如果没有缓存，每次调用都要重复计算，采用缓存已经执行过的去查找，查找到了就直接返回，不需要重新计算 var fn=(function(){ var cache={};//缓存对象 var calc=function(arr){//计算函数 var sum=0; //求和 for(var i=0;i&lt;arr.length;i++){ sum+=arr[i]; } return sum; } return function(){ var args = Array.prototype.slice.call(arguments,0); //arguments 转换成数组 var key=args.join(&quot;,&quot;); //将 args 用逗号连接成字符串 var result , tSum = cache[key]; if(tSum){//如果缓存有 console.log(&#39;从缓存中取：&#39;,cache)//打印方便查看 result = tSum; }else{ //重新计算，并存入缓存同时赋值给 result result = cache[key]=calc(args); console.log(&#39;存入缓存：&#39;,cache)//打印方便查看 } return result; } })(); fn(1,2,3,4,5); fn(1,2,3,4,5); fn(1,2,3,4,5,6); fn(1,2,3,4,5,8); fn(1,2,3,4,5,6);</p>`,35),r=[l];function s(i,c,u,f,p,h){return n(),e("div",null,r)}const g=a(t,[["render",s]]);export{d as __pageData,g as default};
